+func TestBuildRFC822NonASCIIHTMLPartUses8bit(t *testing.T) {
+	raw, err := buildRFC822(mailOptions{
+		From:     "a@b.com",
+		To:       []string{"c@d.com"},
+		Subject:  "Test",
+		Body:     "Plain body",
+		BodyHTML: "<p>Hej åäö</p>",
+	}, nil)
+	if err != nil {
+		t.Fatalf("err: %v", err)
+	}
